#include<bits/stdc++.h>
using namespace std;

string cheng(string A,string B)
{
    string ans="";
    int a[100000], b[100000], c[100000];
    int lena=A.size(),lenb=B.size();
    for(int i=lena-1;i>=0;i--)
        a[lena-i]=A[i]-'0';
    for(int i=lenb-1;i>=0;i--)
        b[lenb-i]=B[i]-'0';
    int len=lena+lenb;
    for(int i=1;i<=lena;i++)
        for(int j= 1;j<=lenb;j++)
            c[i+j-1]+=a[i]*b[j];
    for(int i=1;i<=len;i++)
    {
        c[i+1]+=c[i]/10;
        c[i]%=10;
    }
    while(c[len]==0)len--;
    for(int i=max(1,len);i>=1;i--)
        ans+=c[i]+'0';
    return ans;
}
int main() {
    string a,b;
    cin>>a>>b;
    cout<<cheng(a,b);
  return 0;
}
